/**
 * CSV Parser Library
 * A robust, type-aware CSV parser with support for quoted fields, custom delimiters, and aggregation
 */

export interface CSVOptions {
  /** Field delimiter character (default: ',') */
  delimiter?: string;
  /** Quote character for fields (default: '"') */
  quote?: string;
  /** Line separator (default: '\n') */
  lineSeparator?: string;
  /** If false, don't perform type coercion (default: true) */
  typeCoercion?: boolean;
}

export interface ParseError {
  /** 1-based row number where error occurred */
  row: number;
  /** Error description */
  message: string;
}

export interface CSVResult {
  /** Parsed data as array of objects */
  rows: Record<string, any>[];
  /** Column headers */
  headers: string[];
  /** Parsing errors encountered */
  errors: ParseError[];
  /**
   * Filter rows based on a predicate function
   * @param predicate Function that returns true to include the row
   * @returns Filtered CSVResult with same methods available
   */
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  /**
   * Sum numeric values in a column
   * @param column Column name
   * @returns Sum of numeric values in the column, ignoring non-numeric values
   */
  sum(column: string): number;
  /**
   * Calculate average of numeric values in a column
   * @param column Column name
   * @returns Average of numeric values in the column, ignoring non-numeric values
   */
  average(column: string): number;
  /**
   * Count total rows
   * @returns Number of data rows (excluding header)
   */
  count(): number;
  /**
   * Group rows by a column's values
   * @param column Column name to group by
   * @returns Map where keys are column values and values are arrays of matching rows
   */
  groupBy(column: string): Map<any, Record<string, any>[]>;
}

/**
 * Parse a CSV string into structured data
 * @param input CSV string to parse
 * @param options Parsing options
 * @returns CSVResult object with parsed data and methods
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';
  const shouldCoerce = options.typeCoercion !== false;

  const errors: ParseError[] = [];
  const rows: Record<string, any>[] = [];
  let headers: string[] = [];

  if (!input || input.trim().length === 0) {
    return createCSVResult([], [], [], shouldCoerce);
  }

  // Split input into lines
  const lines = input.split(lineSeparator);

  // Helper function to parse a single line respecting quoted fields
  function parseLine(line: string, lineNumber: number): string[] | null {
    const fields: string[] = [];
    let currentField = '';
    let inQuotes = false;
    let i = 0;

    try {
      while (i < line.length) {
        const char = line[i];

        if (char === quote) {
          if (inQuotes) {
            // Check if this is an escaped quote (two quotes in a row)
            if (i + 1 < line.length && line[i + 1] === quote) {
              currentField += quote;
              i += 2;
              continue;
            } else {
              // End of quoted field
              inQuotes = false;
              i++;
              continue;
            }
          } else {
            // Start of quoted field
            inQuotes = true;
            i++;
            continue;
          }
        } else if (char === delimiter && !inQuotes) {
          // Field separator
          fields.push(currentField.trim());
          currentField = '';
          i++;
          continue;
        } else {
          // Regular character
          currentField += char;
          i++;
        }
      }

      // Add the last field
      fields.push(currentField.trim());

      // Check for unclosed quotes
      if (inQuotes) {
        errors.push({
          row: lineNumber,
          message: 'Unclosed quoted field',
        });
        return null;
      }

      return fields;
    } catch (error) {
      errors.push({
        row: lineNumber,
        message: `Error parsing line: ${error instanceof Error ? error.message : String(error)}`,
      });
      return null;
    }
  }

  // Helper function to coerce types
  function coerceType(value: string): any {
    if (!shouldCoerce) {
      return value;
    }

    // Handle null values
    if (value === '' || value === 'null' || value === 'NULL') {
      return null;
    }

    // Handle booleans
    if (value.toLowerCase() === 'true') {
      return true;
    }
    if (value.toLowerCase() === 'false') {
      return false;
    }

    // Handle numbers
    if (!isNaN(Number(value)) && value !== '') {
      const num = Number(value);
      // Check if it's actually a valid number string
      if (String(num) === value || (value.includes('.') && parseFloat(value) === num)) {
        return num;
      }
      // For integer strings without decimals
      if (!value.includes('.') && /^-?\d+$/.test(value)) {
        return num;
      }
      // For float strings
      if (/^-?\d+\.\d+$/.test(value) || /^-?\d+\.?\d*e[+-]?\d+$/i.test(value)) {
        return num;
      }
    }

    // Default to string
    return value;
  }

  // Parse header line
  const headerLine = parseLine(lines[0], 1);
  if (headerLine === null || headerLine.length === 0) {
    errors.push({
      row: 1,
      message: 'Failed to parse header line',
    });
    return createCSVResult([], [], errors, shouldCoerce);
  }

  headers = headerLine.map((h) => h.trim());

  // Parse data lines
  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip empty lines
    if (line.trim().length === 0) {
      continue;
    }

    const fields = parseLine(line, i + 1);

    if (fields === null) {
      continue; // Error already recorded in parseLine
    }

    // Validate field count matches headers
    if (fields.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue;
    }

    // Create row object
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j++) {
      row[headers[j]] = coerceType(fields[j]);
    }

    rows.push(row);
  }

  return createCSVResult(rows, headers, errors, shouldCoerce);
}

/**
 * Helper function to create a CSVResult object with methods
 */
function createCSVResult(
  rows: Record<string, any>[],
  headers: string[],
  errors: ParseError[],
  shouldCoerce: boolean
): CSVResult {
  const result: CSVResult = {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filteredRows = rows.filter(predicate);
      return createCSVResult(filteredRows, headers, errors, shouldCoerce);
    },

    sum(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let sum = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          sum += value;
        }
      }
      return sum;
    },

    average(column: string): number {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      let sum = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === 'number') {
          sum += value;
          count++;
        }
      }

      return count === 0 ? 0 : sum / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<any, Record<string, any>[]> {
      if (!headers.includes(column)) {
        throw new Error(`Column "${column}" not found`);
      }

      const groups = new Map<any, Record<string, any>[]>();

      for (const row of rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }

      return groups;
    },
  };

  return result;
}

/**
 * Comprehensive test suite for the CSV Parser library
 * Tests are standalone and use basic assertions (throw on failure)
 */

import { parseCSV, CSVOptions } from './csv-parser';

// Test helper functions
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEqual<T>(actual: T, expected: T, message: string): void {
  if (actual !== expected) {
    throw new Error(`Expected ${expected}, but got ${actual}. ${message}`);
  }
}

function assertDeepEqual(actual: any, expected: any, message: string): void {
  const actualStr = JSON.stringify(actual);
  const expectedStr = JSON.stringify(expected);
  if (actualStr !== expectedStr) {
    throw new Error(`Deep equality failed:\nExpected: ${expectedStr}\nActual: ${actualStr}\n${message}`);
  }
}

function assertArrayEqual<T>(actual: T[], expected: T[], message: string): void {
  assertEqual(actual.length, expected.length, `Array length mismatch. ${message}`);
  for (let i = 0; i < actual.length; i++) {
    if (JSON.stringify(actual[i]) !== JSON.stringify(expected[i])) {
      throw new Error(`Array element ${i} mismatch. Expected ${expected[i]}, got ${actual[i]}. ${message}`);
    }
  }
}

function assertThrows(fn: () => void, message: string): void {
  try {
    fn();
    throw new Error(`Expected function to throw but it didn't. ${message}`);
  } catch (error) {
    if (error instanceof Error && error.message.includes("Expected function to throw")) {
      throw error;
    }
    // Expected behavior
  }
}

let testCount = 0;
let passedCount = 0;

function runTest(name: string, fn: () => void): void {
  testCount++;
  try {
    fn();
    console.log(`вњ“ Test ${testCount}: ${name}`);
    passedCount++;
  } catch (error) {
    console.error(`вњ— Test ${testCount}: ${name}`);
    console.error(`  Error: ${error instanceof Error ? error.message : String(error)}`);
  }
}

// ==================== TESTS ====================

console.log('\nрџ“‹ Running CSV Parser Tests\n');

// ========== Basic Parsing ==========
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('BASIC PARSING');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Parse simple CSV with basic data', () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA`;

  const result = parseCSV(csv);

  assertEqual(result.headers.length, 3, 'Should have 3 headers');
  assertArrayEqual(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEqual(result.rows.length, 2, 'Should have 2 data rows');
  assertEqual(result.rows[0].name, 'John', 'First row name should be John');
  assertEqual(result.rows[1].name, 'Jane', 'Second row name should be Jane');
});

runTest('Parse CSV with single column', () => {
  const csv = `id
1
2
3`;

  const result = parseCSV(csv);

  assertEqual(result.headers.length, 1, 'Should have 1 header');
  assertEqual(result.headers[0], 'id', 'Header should be "id"');
  assertEqual(result.rows.length, 3, 'Should have 3 rows');
});

runTest('Parse CSV with single data row', () => {
  const csv = `name,email
Alice,alice@example.com`;

  const result = parseCSV(csv);

  assertEqual(result.headers.length, 2, 'Should have 2 headers');
  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0].name, 'Alice', 'Row name should be Alice');
});

runTest('Handle empty input', () => {
  const result = parseCSV('');

  assertEqual(result.headers.length, 0, 'Should have no headers');
  assertEqual(result.rows.length, 0, 'Should have no rows');
  assertEqual(result.errors.length, 0, 'Should have no errors');
});

runTest('Handle whitespace-only input', () => {
  const result = parseCSV('   \n  \n  ');

  assertEqual(result.headers.length, 0, 'Should have no headers');
  assertEqual(result.rows.length, 0, 'Should have no rows');
});

// ========== Quoted Fields ==========
console.log('\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('QUOTED FIELDS');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Parse CSV with quoted fields containing commas', () => {
  const csv = `name,description,price
"Smith, John","A great product, really",19.99
"Doe, Jane","Another, amazing item",29.99`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'Smith, John', 'Name should include comma');
  assertEqual(result.rows[0].description, 'A great product, really', 'Description should include comma');
  assertEqual(result.rows[0].price, 19.99, 'Price should be numeric');
});

runTest('Parse CSV with quoted fields containing newlines (multiline)', () => {
  const csv = `id,text
1,"Hello
World"
2,"Goodbye
Moon"`;

  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should parse multiline fields');
  assert(result.rows[0].text.includes('\n'), 'Text should contain newline');
});

runTest('Parse fields with quotes at boundaries', () => {
  const csv = `data
"value"
"another"`;

  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, 'Should have 2 rows');
  assertEqual(result.rows[0].data, 'value', 'Should strip outer quotes');
});

runTest('Handle empty quoted fields', () => {
  const csv = `a,b,c
1,"",3
4,"",6`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].b, null, 'Empty quoted field should be null with type coercion');
  assertEqual(result.rows[1].b, null, 'Empty quoted field should be null with type coercion');
});

// ========== Escaped Quotes ==========
console.log('\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('ESCAPED QUOTES');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Handle escaped quotes (double quotes) within quoted fields', () => {
  const csv = `name,quote
"John ""The King"" Doe","He said ""Hello"""`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].name, 'John "The King" Doe', 'Double quotes should become single');
  assertEqual(result.rows[0].quote, 'He said "Hello"', 'Escaped quotes should be unescaped');
});

runTest('Handle multiple escaped quotes in sequence', () => {
  const csv = `text
""""""`);

  const result = parseCSV(csv);

  assertEqual(result.rows[0].text, '"""', 'Three escaped quotes should become three literal quotes');
});

runTest('Handle escaped quotes at start and end', () => {
  const csv = `text
"""start and end"""`);

  const result = parseCSV(csv);

  assertEqual(result.rows[0].text, '"start and end"', 'Escaped quotes at boundaries');
});

// ========== Custom Delimiters ==========
console.log('\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('CUSTOM DELIMITERS');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Parse CSV with semicolon delimiter', () => {
  const csv = `name;age;city
John;30;NYC
Jane;25;LA`;

  const result = parseCSV(csv, { delimiter: ';' });

  assertEqual(result.headers[0], 'name', 'First header');
  assertEqual(result.rows[0].city, 'NYC', 'Should parse with semicolon delimiter');
  assertEqual(result.rows[1].age, 25, 'Age should be coerced to number');
});

runTest('Parse CSV with pipe delimiter', () => {
  const csv = `id|name|status
1|active|OK
2|inactive|PENDING`;

  const result = parseCSV(csv, { delimiter: '|' });

  assertEqual(result.rows[0].name, 'active', 'Name should be parsed correctly');
  assertEqual(result.rows[1].status, 'PENDING', 'Status should match');
});

runTest('Parse CSV with custom quote character', () => {
  const csv = `name,description
'John Smith','A person with comma, in data'
'Jane Doe','Another person, here'`;

  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0].name, 'John Smith', 'Single quotes should work as quote character');
  assertEqual(result.rows[0].description, 'A person with comma, in data', 'Should handle commas in single-quoted fields');
});

runTest('Parse CSV with custom line separator (Windows CRLF)', () => {
  const csv = `name,age\r\nAlice,28\r\nBob,35`;

  const result = parseCSV(csv, { lineSeparator: '\r\n' });

  assertEqual(result.rows.length, 2, 'Should parse CRLF line endings');
  assertEqual(result.rows[0].name, 'Alice', 'First row should be correct');
});

// ========== Type Coercion ==========
console.log('\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('TYPE COERCION');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Coerce integer strings to numbers', () => {
  const csv = `id,count
1,100
2,200`;

  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].id, 'number', 'id should be number');
  assertEqual(result.rows[0].id, 1, 'id value should be 1');
  assertEqual(typeof result.rows[0].count, 'number', 'count should be number');
  assertEqual(result.rows[0].count, 100, 'count value should be 100');
});

runTest('Coerce floating point strings to numbers', () => {
  const csv = `price,rate
19.99,0.95
29.50,1.05`;

  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].price, 'number', 'price should be number');
  assertEqual(result.rows[0].price, 19.99, 'price value should match');
  assert(Math.abs(result.rows[0].rate - 0.95) < 0.0001, 'rate should be approximately 0.95');
});

runTest('Coerce "true" string to boolean true', () => {
  const csv = `name,active
John,true
Jane,True
Bob,TRUE`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].active, true, 'lowercase true should be boolean');
  assertEqual(result.rows[1].active, true, 'Title case True should be boolean');
  assertEqual(result.rows[2].active, true, 'UPPERCASE TRUE should be boolean');
});

runTest('Coerce "false" string to boolean false', () => {
  const csv = `name,active
John,false
Jane,False
Bob,FALSE`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].active, false, 'lowercase false should be boolean');
  assertEqual(result.rows[1].active, false, 'Title case False should be boolean');
  assertEqual(result.rows[2].active, false, 'UPPERCASE FALSE should be boolean');
});

runTest('Coerce "null" and "NULL" strings to null', () => {
  const csv = `a,b,c
null,NULL,`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].a, null, '"null" should become null');
  assertEqual(result.rows[0].b, null, '"NULL" should become null');
  assertEqual(result.rows[0].c, null, 'empty string should become null');
});

runTest('Keep other strings as strings', () => {
  const csv = `text,code
hello,ABC123
world,XYZ789`;

  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0].text, 'string', 'text should remain string');
  assertEqual(result.rows[0].text, 'hello', 'text value should match');
  assertEqual(typeof result.rows[0].code, 'string', 'code should remain string');
});

runTest('Disable type coercion with option', () => {
  const csv = `id,active,value
1,true,19.99`;

  const result = parseCSV(csv, { typeCoercion: false });

  assertEqual(typeof result.rows[0].id, 'string', 'id should remain string when coercion disabled');
  assertEqual(result.rows[0].id, '1', 'id value should be "1"');
  assertEqual(result.rows[0].active, 'true', 'active should remain string');
  assertEqual(result.rows[0].value, '19.99', 'value should remain string');
});

runTest('Handle negative numbers', () => {
  const csv = `value
-100
-99.5
-1`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].value, -100, 'Negative integer should be coerced');
  assertEqual(result.rows[1].value, -99.5, 'Negative float should be coerced');
  assertEqual(result.rows[2].value, -1, 'Negative single digit should be coerced');
});

runTest('Handle scientific notation', () => {
  const csv = `value
1e5
1.5e-3
-2.5E+2`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].value, 100000, 'Scientific notation 1e5 should work');
  assert(Math.abs(result.rows[1].value - 0.0015) < 0.00001, 'Scientific notation 1.5e-3 should work');
  assertEqual(result.rows[2].value, -250, 'Scientific notation -2.5E+2 should work');
});

// ========== Error Handling ==========
console.log('\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');
console.log('ERROR HANDLING');
console.log('в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ');

runTest('Collect error for unclosed quote', () => {
  const csv = `name,email
"John Doe,john@example.com`;

  const result = parseCSV(csv);

  assert(result.errors.length > 0, 'Should have errors');
  assert(result.errors[0].message.includes('Unclosed'), 'Should mention unclosed quotes');
  assertEqual(result.errors[0].row, 2, 'Error should be on row 2');
});

runTest('Collect error for field count mismatch', () => {
  const csv = `name,age,city
John,30
Jane,25,LA,Extra`;

