runTest('Handle very large field values', () => {
  const largeValue = 'x'.repeat(10000);
  const csv = `name,data
"John","${largeValue}"`;

  const result = parseCSV(csv);

  assertEqual(result.rows[0].data, largeValue, 'Should handle large fields');
  assertEqual(result.rows[0].data.length, 10000, 'Large field length should match');
