runTest('Handle many columns', () => {
  let csv = '';
  const colCount = 100;
  for (let i = 0; i < colCount; i++) {
    if (i > 0) csv += ',';
    csv += `col${i}`;
  }
  csv += '\n';
  for (let i = 0; i < colCount; i++) {
    if (i > 0) csv += ',';
    csv += i.toString();
  }

  const result = parseCSV(csv);

  assertEqual(result.headers.length, colCount, `Should handle ${colCount} columns`);
  assertEqual(result.rows.length, 1, 'Should have 1 row');
  assertEqual(result.rows[0].col0, 0, 'First column value should be 0');
  assertEqual(result.rows[0].col99, 99, 'Last column value should be 99');
});

runTest('Handle many rows', () => {
  let csv = 'id,value\n';
  const rowCount = 1000;
  for (let i = 1; i <= rowCount; i++) {
    csv += `${i},${i * 10}\n`;
  }

  const result = parseCSV(csv);

  assertEqual(result.rows.length, rowCount, `Should handle ${rowCount} rows`);
  assertEqual(result.rows[0].id, 1, 'First row id');
  assertEqual(result.rows[rowCount - 1].id, rowCount, 'Last row id');
});

