### Aggregation - GroupBy

```typescript
const csv = `name,department,salary
John,Engineering,80000
Jane,Sales,70000
Bob,Engineering,85000
Alice,Sales,72000`;

const result = parseCSV(csv);

const byDept = result.groupBy('department');
console.log(byDept.size);
// 2

console.log(byDept.get('Engineering'));
// [
//   { name: 'John', department: 'Engineering', salary: 80000 },
//   { name: 'Bob', department: 'Engineering', salary: 85000 }
// ]

// Get average salary by department
for (const [dept, employees] of byDept) {
  const salaries = employees.reduce((sum, e) => sum + e.salary, 0);
  const avgSalary = salaries / employees.length;
  console.log(`${dept}: $${avgSalary.toFixed(2)}`);
}
// Engineering: $82500.00
// Sales: $71000.00

// GroupBy on filtered data
const seniorEngineers = result
  .filter(row => row.salary > 82000)
  .groupBy('department');
```

### Complex Workflow

```typescript
const csv = `product,category,price,quantity,active
Laptop,Electronics,999.99,5,true
Mouse,Electronics,29.99,50,true
Keyboard,Electronics,99.99,30,false
Desk,Furniture,299.99,3,false
Chair,Furniture,199.99,10,true
Monitor,Electronics,399.99,8,false`;

const result = parseCSV(csv);

// Get all active products in Electronics
const activeElectronics = result
  .filter(row => row.active === true)
  .filter(row => row.category === 'Electronics');

console.log(activeElectronics.count());
// 2

// Calculate total value of active inventory
const totalValue = activeElectronics.rows.reduce(
  (sum, row) => sum + (row.price * row.quantity),
  0
);
console.log(`Total active inventory value: $${totalValue.toFixed(2)}`);
// Total active inventory value: $1649.50

// Group all products by category
const byCategory = result.groupBy('category');
for (const [category, products] of byCategory) {
  const avgPrice = products.reduce((sum, p) => sum + p.price, 0) / products.length;
  console.log(`${category}: ${products.length} items, avg price $${avgPrice.toFixed(2)}`);
}
// Electronics: 4 items, avg price $382.49
// Furniture: 2 items, avg price $249.99
```

## Type Coercion Details

The parser automatically converts values based on the following rules:

| Input Value | Output Type | Output Value |
|------------|------------|------------|
| `"123"` | number | `123` |
| `"45.67"` | number | `45.67` |
| `"-100"` | number | `--100` |
| `"1e5"` | number | `100000` |
| `"true"` / `"True"` / `"TRUE"` | boolean | `true` |
| `"false"` / `"False"` / `"FALSE"` | boolean | `false` |
| `""` (empty) | null | `null` |
| `"null"` / `"NULL"` | null | `null` |
| `"hello"` | string | `"hello"` |
| `"not-a-number"` | string | `"not-a-number"` |

## Error Handling

The parser collects errors and continues processing valid rows:

```typescript
const csv = `name,age,city
"John,30,NYC
Jane,25,LA
Bob`;

const result = parseCSV(csv);

console.log(result.rows);
// [
//   { name: 'Jane', age: 25, city: 'LA' },
//   { name: 'Bob', age: undefined, city: undefined }
// ]

console.log(result.errors);
// [
//   { row: 2, message: 'Unclosed quoted field' },
//   { row: 4, message: 'Expected 3 fields but got 1' }
// ]
```

